from vex import patterns

@vex_client.listener(EventType.TOOL_CALL)
def validate_tool_inputs(event):
    tool_input = event.payload.get('input', '')

    # Block SQL injection attempts
    if patterns.SQL_INJECTION.match(tool_input):
        vex_client.block('SQL_INJECTION_DETECTED', evidence=tool_input)
        return

    # Enforce tenant isolation
    tenant_id = event.context.get('tenant_id')
    if patterns.TENANT_CROSSOVER.match(tool_input, tenant_id):
        vex_client.block('TENANT_ISOLATION_VIOLATION')

    # PII redaction for GDPR/CCPA
    pii_entities = patterns.PII_ENTITIES.scan(tool_input)
    if pii_entities:
        vex_client.alert('PII_IN_TOOL_INPUT', entities=pii_entities)

@vex_client.listener([EventType.STATE_PERSIST, EventType.STATE_LOAD])
def monitor_serialization(event):
    try:
        state = event.payload['state']

        # Validate Granite output format consistency
        if not validate_granite_format(state.get('model_output')):
            vex_client.block('INVALID_MODEL_FORMAT')

        # Check data residency by tenant region
        tenant_region = event.context['tenant_region']
        if state.get('storage_location') != tenant_region:
            vex_client.block('DATA_RESIDENCY_VIOLATION')

    except SerializationError as e:
        vex_client.critical('STATE_SERIALIZATION_ERROR', error=str(e))
        vex_client.block('SERIALIZATION_FAILURE')

def validate_granite_format(output):
    return (output.get('format') == 'json' and 
            isinstance(output.get('data'), dict) and
            output.get('version') == '1.0')
